    /**
     * @method
     * @name bitopro#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://github.com/bitoex/bitopro-offical-api-docs/blob/master/api/v3/public/get_currency_info.md
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetProvisioningCurrencies(parameters)).join();
            //
            //     {
            //         "data":[
            //             {
            //                 "currency":"eth",
            //                 "withdrawFee":"0.007",
            //                 "minWithdraw":"0.001",
            //                 "maxWithdraw":"1000",
            //                 "maxDailyWithdraw":"2000",
            //                 "withdraw":true,
            //                 "deposit":true,
            //                 "depositConfirmation":"12"
            //             }
            //         ]
            //     }
            //
            Object currencies = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseCurrencies(currencies);
        });

    }

    public Object parseCurrency(Object rawCurrency)
    {
        Object fiatCurrencies = this.safeList(this.options, "fiatCurrencies", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object currencyId = this.safeString(rawCurrency, "currency");
        Object code = this.safeCurrencyCode(currencyId);
        Object deposit = this.safeBool(rawCurrency, "deposit");
        Object withdraw = this.safeBool(rawCurrency, "withdraw");
        Object isFiat = this.inArray(code, fiatCurrencies);
        final Object finalDeposit = deposit;
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", currencyId );
            put( "code", code );
            put( "info", rawCurrency );
            put( "type", ((Helpers.isTrue(isFiat))) ? "fiat" : "crypto" );
            put( "name", null );
            put( "active", Helpers.isTrue(finalDeposit) && Helpers.isTrue(withdraw) );
            put( "deposit", finalDeposit );
            put( "withdraw", withdraw );
            put( "fee", BitoproCore.this.safeNumber(rawCurrency, "withdrawFee") );
            put( "precision", null );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", BitoproCore.this.safeNumber(rawCurrency, "minWithdraw") );
                    put( "max", BitoproCore.this.safeNumber(rawCurrency, "maxWithdraw") );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", null );
        }});
    }

