    public Object parseMarket(Object market)
    {
        Object active = !Helpers.isTrue(this.safeBool(market, "maintain"));
        Object id = this.safeString(market, "pair");
        Object uppercaseId = ((String)id).toUpperCase();
        Object baseId = this.safeString(market, "base");
        Object quoteId = this.safeString(market, "quote");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        Object limits = new java.util.HashMap<String, Object>() {{
            put( "amount", new java.util.HashMap<String, Object>() {{
                put( "min", BitoproCore.this.safeNumber(market, "minLimitBaseAmount") );
                put( "max", BitoproCore.this.safeNumber(market, "maxLimitBaseAmount") );
            }} );
            put( "price", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "cost", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "leverage", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
        }};
        final Object finalBase = base;
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "uppercaseId", uppercaseId );
            put( "symbol", symbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "baseId", finalBase );
            put( "quoteId", quote );
            put( "settle", null );
            put( "settleId", null );
            put( "type", "spot" );
            put( "spot", true );
            put( "margin", false );
            put( "swap", false );
            put( "future", false );
            put( "option", false );
            put( "contract", false );
            put( "linear", null );
            put( "inverse", null );
            put( "contractSize", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "limits", limits );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "price", BitoproCore.this.parseNumber(BitoproCore.this.parsePrecision(BitoproCore.this.safeString(market, "quotePrecision"))) );
                put( "amount", BitoproCore.this.parseNumber(BitoproCore.this.parsePrecision(BitoproCore.this.safeString(market, "basePrecision"))) );
            }} );
            put( "active", active );
            put( "created", null );
            put( "info", market );
        }};
    }

