    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //         {
        //                 "timestamp":1644651458,
        //                 "price":"1180785.00000000",
        //                 "amount":"0.00020000",
        //                 "isBuyer":false
        //         }
        //
        // fetchMyTrades
        //         {
        //                 "tradeId":"5685030251",
        //                 "orderId":"9669168142",
        //                 "price":"11821.8",
        //                 "action":"SELL",
        //                 "baseAmount":"0.01",
        //                 "quoteAmount":"118.218",
        //                 "fee":"0.236436",
        //                 "feeSymbol":"BNB",
        //                 "isTaker":true,
        //                 "timestamp":1644905714862,
        //                 "createdTimestamp":1644905714862
        //         }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(trade, "tradeId");
        Object orderId = this.safeString(trade, "orderId");
        Object timestamp = null;
        if (Helpers.isTrue(Helpers.isEqual(id, null)))
        {
            timestamp = this.safeTimestamp(trade, "timestamp");
        } else
        {
            timestamp = this.safeInteger(trade, "timestamp");
        }
        Object marketId = this.safeString(trade, "pair");
        market = this.safeMarket(marketId, market);
        Object symbol = this.safeString(market, "symbol");
        Object price = this.safeString(trade, "price");
        Object type = this.safeStringLower(trade, "type");
        Object side = this.safeStringLower(trade, "action");
        if (Helpers.isTrue(Helpers.isEqual(side, null)))
        {
            Object isBuyer = this.safeBool(trade, "isBuyer");
            if (Helpers.isTrue(isBuyer))
            {
                side = "buy";
            } else
            {
                side = "sell";
            }
        }
        Object amount = this.safeString(trade, "amount");
        if (Helpers.isTrue(Helpers.isEqual(amount, null)))
        {
            amount = this.safeString(trade, "baseAmount");
        }
        Object fee = null;
        Object feeAmount = this.safeString(trade, "fee");
        Object feeSymbol = this.safeCurrencyCode(this.safeString(trade, "feeSymbol"));
        if (Helpers.isTrue(!Helpers.isEqual(feeAmount, null)))
        {
            final Object finalFeeAmount = feeAmount;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeAmount );
                put( "currency", feeSymbol );
                put( "rate", null );
            }};
        }
        Object isTaker = this.safeBool(trade, "isTaker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(isTaker, null)))
        {
            if (Helpers.isTrue(isTaker))
            {
                takerOrMaker = "taker";
            } else
            {
                takerOrMaker = "maker";
            }
        }
        final Object finalId = id;
        final Object finalTimestamp = timestamp;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalSide = side;
        final Object finalAmount = amount;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", finalId );
            put( "info", trade );
            put( "order", orderId );
            put( "timestamp", finalTimestamp );
            put( "datetime", BitoproCore.this.iso8601(finalTimestamp) );
            put( "symbol", symbol );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "type", type );
            put( "side", finalSide );
            put( "price", price );
            put( "amount", finalAmount );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

