    public Object parseTransactionStatus(Object status)
    {
        Object states = new java.util.HashMap<String, Object>() {{
            put( "COMPLETE", "ok" );
            put( "INVALID", "failed" );
            put( "PROCESSING", "pending" );
            put( "WAIT_PROCESS", "pending" );
            put( "FAILED", "failed" );
            put( "EXPIRED", "failed" );
            put( "CANCELLED", "failed" );
            put( "EMAIL_VERIFICATION", "pending" );
            put( "WAIT_CONFIRMATION", "pending" );
        }};
        return this.safeString(states, status, status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        //    {
        //        "serial": "20220214X766799",
        //        "timestamp": "1644833015053",
        //        "address": "bnb1xml62k5a9dcewgc542fha75fyxdcp0zv8eqfsh",
        //        "amount": "0.20000000",
        //        "fee": "0.00000000",
        //        "total": "0.20000000",
        //        "status": "COMPLETE",
        //        "txid": "A3CC4F6828CC752B9F3737F48B5826B9EC2857040CB5141D0CC955F7E53DB6D9",
        //        "message": "778553959",
        //        "protocol": "MAIN",
        //        "id": "2905906537"
        //    }
        //
        // fetchWithdrawals || fetchWithdraw
        //
        //    {
        //        "serial": "20220215BW14069838",
        //        "timestamp": "1644907716044",
        //        "address": "TKrwMaZaGiAvtXCFT41xHuusNcs4LPWS7w",
        //        "amount": "8.00000000",
        //        "fee": "2.00000000",
        //        "total": "10.00000000",
        //        "status": "COMPLETE",
        //        "txid": "50bf250c71a582f40cf699fb58bab978437ea9bdf7259ff8072e669aab30c32b",
        //        "protocol": "TRX",
        //        "id": "9925310345"
        //    }
        //
        // withdraw
        //
        //    {
        //        "serial": "20220215BW14069838",
        //        "currency": "USDT",
        //        "protocol": "TRX",
        //        "address": "TKrwMaZaGiAvtXCFT41xHuusNcs4LPWS7w",
        //        "amount": "8",
        //        "fee": "2",
        //        "total": "10"
        //    }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(transaction, "coin");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestamp = this.safeInteger(transaction, "timestamp");
        Object address = this.safeString(transaction, "address");
        Object tag = this.safeString(transaction, "message");
        Object status = this.safeString(transaction, "status");
        Object networkId = this.safeString(transaction, "protocol");
        if (Helpers.isTrue(Helpers.isEqual(networkId, "MAIN")))
        {
            networkId = code;
        }
        final Object finalNetworkId = networkId;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", BitoproCore.this.safeString(transaction, "serial") );
            put( "txid", BitoproCore.this.safeString(transaction, "txid") );
            put( "type", null );
            put( "currency", code );
            put( "network", BitoproCore.this.networkIdToCode(finalNetworkId, code) );
            put( "amount", BitoproCore.this.safeNumber(transaction, "total") );
            put( "status", BitoproCore.this.parseTransactionStatus(status) );
            put( "timestamp", timestamp );
            put( "datetime", BitoproCore.this.iso8601(timestamp) );
            put( "address", address );
            put( "addressFrom", null );
            put( "addressTo", address );
            put( "tag", tag );
            put( "tagFrom", null );
            put( "tagTo", tag );
            put( "updated", null );
            put( "comment", null );
            put( "internal", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", BitoproCore.this.safeNumber(transaction, "fee") );
                put( "rate", null );
            }} );
        }};
    }

